SELECT id, model, event_name, script_lang, script_code, status, remark, create_time, update_time
FROM sys_script


        AND (
            model ILIKE CONCAT('%', #{query.keyword}, '%')
            OR event_name ILIKE CONCAT('%', #{query.keyword}, '%')
            OR remark ILIKE CONCAT('%', #{query.keyword}, '%')
        )


        AND model = #{query.model}


        AND event_name = #{query.eventName}


        AND status = #{query.status}


ORDER BY id DESC
